// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/**
 * @title CrowdfundingPlatform
 * @dev A decentralized crowdfunding platform with milestone-based fund release
 */
contract CrowdfundingPlatform {
    enum CampaignStatus { Active, Completed, Cancelled, Funded }
    enum MilestoneStatus { Pending, Completed, Verified, Failed }

    struct Campaign {
        uint256 id;
        address creator;
        string title;
        string description;
        uint256 targetAmount;
        uint256 deadline;
        uint256 amountRaised;
        CampaignStatus status;
        string ipfsHash; // IPFS hash for campaign media/details
        uint256 createdAt;
    }

    struct Milestone {
        uint256 id;
        uint256 campaignId;
        string title;
        string description;
        uint256 releaseAmount;
        uint256 deadline;
        MilestoneStatus status;
        uint256 votes;
        uint256 totalVoters;
    }

    struct Donation {
        uint256 id;
        uint256 campaignId;
        address donor;
        uint256 amount;
        uint256 timestamp;
        bool refunded;
    }

    // State variables
    uint256 public campaignCounter = 0;
    uint256 public donationCounter = 0;
    uint256 public platformFeePercentage = 2; // 2% platform fee

    mapping(uint256 => Campaign) public campaigns;
    mapping(uint256 => Milestone[]) public campaignMilestones;
    mapping(uint256 => Donation[]) public campaignDonations;
    mapping(uint256 => mapping(address => uint256)) public donorContributions;
    mapping(uint256 => mapping(uint256 => mapping(address => bool))) public milestoneVotes; // campaignId => milestoneId => voter => hasVoted
    mapping(address => uint256[]) public creatorCampaigns;
    mapping(address => uint256) public creatorWithdrawals;

    address public platformOwner;
    uint256 public platformFeesCollected = 0;

    // Events
    event CampaignCreated(
        uint256 indexed campaignId,
        address indexed creator,
        string title,
        uint256 targetAmount,
        uint256 deadline
    );

    event DonationMade(
        uint256 indexed campaignId,
        address indexed donor,
        uint256 amount,
        uint256 timestamp
    );

    event MilestoneCreated(
        uint256 indexed campaignId,
        uint256 indexed milestoneId,
        string title,
        uint256 releaseAmount
    );

    event MilestoneVoteCast(
        uint256 indexed campaignId,
        uint256 indexed milestoneId,
        address indexed voter,
        bool approved
    );

    event MilestoneVerified(
        uint256 indexed campaignId,
        uint256 indexed milestoneId,
        uint256 releaseAmount
    );

    event FundsWithdrawn(
        address indexed creator,
        uint256 campaignId,
        uint256 amount
    );

    event CampaignCancelled(
        uint256 indexed campaignId,
        string reason
    );

    event RefundProcessed(
        uint256 indexed campaignId,
        address indexed donor,
        uint256 amount
    );

    // Modifiers
    modifier onlyPlatformOwner() {
        require(msg.sender == platformOwner, "Only platform owner can call this");
        _;
    }

    modifier campaignExists(uint256 _campaignId) {
        require(_campaignId > 0 && _campaignId <= campaignCounter, "Campaign does not exist");
        _;
    }

    modifier onlyCreator(uint256 _campaignId) {
        require(campaigns[_campaignId].creator == msg.sender, "Only creator can call this");
        _;
    }

    constructor() {
        platformOwner = msg.sender;
    }

    /**
     * @dev Create a new campaign
     */
    function createCampaign(
        string memory _title,
        string memory _description,
        uint256 _targetAmount,
        uint256 _durationDays,
        string memory _ipfsHash
    ) external returns (uint256) {
        require(_targetAmount > 0, "Target amount must be greater than 0");
        require(_durationDays > 0, "Duration must be greater than 0");

        campaignCounter++;
        uint256 campaignId = campaignCounter;
        uint256 deadline = block.timestamp + (_durationDays * 1 days);

        campaigns[campaignId] = Campaign({
            id: campaignId,
            creator: msg.sender,
            title: _title,
            description: _description,
            targetAmount: _targetAmount,
            deadline: deadline,
            amountRaised: 0,
            status: CampaignStatus.Active,
            ipfsHash: _ipfsHash,
            createdAt: block.timestamp
        });

        creatorCampaigns[msg.sender].push(campaignId);

        emit CampaignCreated(campaignId, msg.sender, _title, _targetAmount, deadline);
        return campaignId;
    }

    /**
     * @dev Donate to a campaign
     */
    function donate(uint256 _campaignId) external payable campaignExists(_campaignId) {
        require(msg.value > 0, "Donation amount must be greater than 0");

        Campaign storage campaign = campaigns[_campaignId];
        require(campaign.status == CampaignStatus.Active, "Campaign is not active");
        require(block.timestamp <= campaign.deadline, "Campaign deadline has passed");

        donationCounter++;
        campaign.amountRaised += msg.value;
        donorContributions[_campaignId][msg.sender] += msg.value;

        campaignDonations[_campaignId].push(Donation({
            id: donationCounter,
            campaignId: _campaignId,
            donor: msg.sender,
            amount: msg.value,
            timestamp: block.timestamp,
            refunded: false
        }));

        // Mark campaign as funded if target is reached
        if (campaign.amountRaised >= campaign.targetAmount) {
            campaign.status = CampaignStatus.Funded;
        }

        emit DonationMade(_campaignId, msg.sender, msg.value, block.timestamp);
    }

    /**
     * @dev Create a milestone for a campaign
     */
    function createMilestone(
        uint256 _campaignId,
        string memory _title,
        string memory _description,
        uint256 _releaseAmount,
        uint256 _durationDays
    ) external campaignExists(_campaignId) onlyCreator(_campaignId) {
        require(_releaseAmount > 0, "Release amount must be greater than 0");
        require(_durationDays > 0, "Duration must be greater than 0");

        Campaign storage campaign = campaigns[_campaignId];
        require(campaign.status == CampaignStatus.Funded, "Campaign must be funded");

        Milestone memory newMilestone = Milestone({
            id: campaignMilestones[_campaignId].length,
            campaignId: _campaignId,
            title: _title,
            description: _description,
            releaseAmount: _releaseAmount,
            deadline: block.timestamp + (_durationDays * 1 days),
            status: MilestoneStatus.Pending,
            votes: 0,
            totalVoters: 0
        });

        campaignMilestones[_campaignId].push(newMilestone);

        emit MilestoneCreated(_campaignId, newMilestone.id, _title, _releaseAmount);
    }

    /**
     * @dev Vote on milestone completion
     */
    function voteMilestone(
        uint256 _campaignId,
        uint256 _milestoneId,
        bool _approve
    ) external campaignExists(_campaignId) {
        require(_milestoneId < campaignMilestones[_campaignId].length, "Milestone does not exist");
        require(donorContributions[_campaignId][msg.sender] > 0, "Must be a donor to vote");
        require(!milestoneVotes[_campaignId][_milestoneId][msg.sender], "Already voted");

        Milestone storage milestone = campaignMilestones[_campaignId][_milestoneId];
        require(milestone.status == MilestoneStatus.Pending, "Milestone is not pending");

        milestoneVotes[_campaignId][_milestoneId][msg.sender] = true;
        milestone.totalVoters++;

        if (_approve) {
            milestone.votes++;
        }

        // Auto-verify if 80% of donors approve
        if (milestone.votes > (campaignDonations[_campaignId].length * 80 / 100)) {
            milestone.status = MilestoneStatus.Verified;
            emit MilestoneVerified(_campaignId, _milestoneId, milestone.releaseAmount);
        }

        emit MilestoneVoteCast(_campaignId, _milestoneId, msg.sender, _approve);
    }

    /**
     * @dev Withdraw funds for verified milestone
     */
    function withdrawMilestoneFunds(
        uint256 _campaignId,
        uint256 _milestoneId
    ) external campaignExists(_campaignId) onlyCreator(_campaignId) {
        require(_milestoneId < campaignMilestones[_campaignId].length, "Milestone does not exist");

        Milestone storage milestone = campaignMilestones[_campaignId][_milestoneId];
        require(milestone.status == MilestoneStatus.Verified, "Milestone not verified");

        Campaign storage campaign = campaigns[_campaignId];
        uint256 platformFee = (milestone.releaseAmount * platformFeePercentage) / 100;
        uint256 creatorAmount = milestone.releaseAmount - platformFee;

        milestone.status = MilestoneStatus.Completed;
        platformFeesCollected += platformFee;
        creatorWithdrawals[msg.sender] += creatorAmount;

        (bool success, ) = msg.sender.call{value: creatorAmount}("");
        require(success, "Transfer failed");

        emit FundsWithdrawn(msg.sender, _campaignId, creatorAmount);
    }

    /**
     * @dev Cancel campaign and refund donors
     */
    function cancelCampaign(uint256 _campaignId) external campaignExists(_campaignId) onlyCreator(_campaignId) {
        Campaign storage campaign = campaigns[_campaignId];
        require(campaign.status != CampaignStatus.Cancelled, "Campaign already cancelled");

        campaign.status = CampaignStatus.Cancelled;

        // Refund all donors
        Donation[] storage donations = campaignDonations[_campaignId];
        for (uint256 i = 0; i < donations.length; i++) {
            if (!donations[i].refunded) {
                donations[i].refunded = true;
                (bool success, ) = donations[i].donor.call{value: donations[i].amount}("");
                require(success, "Refund failed");
                emit RefundProcessed(_campaignId, donations[i].donor, donations[i].amount);
            }
        }

        emit CampaignCancelled(_campaignId, "Campaign cancelled by creator");
    }

    /**
     * @dev Refund donors if campaign deadline passed without funding
     */
    function refundDonors(uint256 _campaignId) external campaignExists(_campaignId) {
        Campaign storage campaign = campaigns[_campaignId];
        require(block.timestamp > campaign.deadline, "Campaign still active");
        require(campaign.status == CampaignStatus.Active, "Campaign not active");
        require(campaign.amountRaised < campaign.targetAmount, "Campaign was funded");

        campaign.status = CampaignStatus.Cancelled;

        Donation[] storage donations = campaignDonations[_campaignId];
        for (uint256 i = 0; i < donations.length; i++) {
            if (!donations[i].refunded) {
                donations[i].refunded = true;
                (bool success, ) = donations[i].donor.call{value: donations[i].amount}("");
                require(success, "Refund failed");
                emit RefundProcessed(_campaignId, donations[i].donor, donations[i].amount);
            }
        }
    }

    /**
     * @dev Withdraw platform fees
     */
    function withdrawPlatformFees() external onlyPlatformOwner {
        uint256 amount = platformFeesCollected;
        platformFeesCollected = 0;
        (bool success, ) = platformOwner.call{value: amount}("");
        require(success, "Withdrawal failed");
    }

    /**
     * @dev Get campaign details
     */
    function getCampaign(uint256 _campaignId) external view campaignExists(_campaignId) returns (Campaign memory) {
        return campaigns[_campaignId];
    }

    /**
     * @dev Get campaign milestones
     */
    function getCampaignMilestones(uint256 _campaignId) external view campaignExists(_campaignId) returns (Milestone[] memory) {
        return campaignMilestones[_campaignId];
    }

    /**
     * @dev Get campaign donations
     */
    function getCampaignDonations(uint256 _campaignId) external view campaignExists(_campaignId) returns (Donation[] memory) {
        return campaignDonations[_campaignId];
    }

    /**
     * @dev Get creator's campaigns
     */
    function getCreatorCampaigns(address _creator) external view returns (uint256[] memory) {
        return creatorCampaigns[_creator];
    }
}

contracts/CrowdfundingEscrow.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/**
 * @title CrowdfundingEscrow
 * @dev Escrow-based crowdfunding with admin-controlled milestone releases.
 *      Funds are held until the platform admin approves a withdrawal request
 *      backed by IPFS-stored proof. Every approval is permanently on-chain.
 */
contract CrowdfundingEscrow {
    // ─────────────────────────────────────────────────────────────────────────
    // Enums
    // ─────────────────────────────────────────────────────────────────────────

    enum CampaignStatus  { Active, Funded, Completed, Cancelled }
    enum RequestStatus   { Pending, Approved, Rejected }

    // ─────────────────────────────────────────────────────────────────────────
    // Structs
    // ─────────────────────────────────────────────────────────────────────────

    struct Campaign {
        uint256 id;
        address payable creator;
        uint256 targetAmount;
        uint256 amountRaised;
        uint256 deadline;
        CampaignStatus status;
        string ipfsMetadataHash; // IPFS CID of campaign docs uploaded at creation
        uint256 createdAt;
    }

    struct WithdrawalRequest {
        uint256 id;
        uint256 campaignId;
        uint256 requestedAmount;
        string proofIpfsHash;    // IPFS CID of proof documents (invoice, receipt, etc.)
        RequestStatus status;
        string rejectionReason;
        uint256 createdAt;
    }

    // ─────────────────────────────────────────────────────────────────────────
    // State
    // ─────────────────────────────────────────────────────────────────────────

    address public admin;
    uint256 public platformFeePercent = 2;   // 2% taken on each approved release
    uint256 public platformFeesCollected;
    uint256 public campaignCounter;

    mapping(uint256 => Campaign) public campaigns;

    // Donor-level tracking
    mapping(uint256 => address[]) private _campaignDonors;
    mapping(uint256 => uint256[]) private _campaignDonationAmounts;
    mapping(uint256 => mapping(address => uint256)) public donorContributions;

    // Withdrawal requests per campaign
    mapping(uint256 => WithdrawalRequest[]) private _withdrawalRequests;

    // Creator → campaign IDs
    mapping(address => uint256[]) public creatorCampaigns;

    // ─────────────────────────────────────────────────────────────────────────
    // Events
    // ─────────────────────────────────────────────────────────────────────────

    event CampaignCreated(
        uint256 indexed campaignId,
        address indexed creator,
        uint256 targetAmount,
        uint256 deadline,
        string ipfsMetadataHash
    );

    event DonationReceived(
        uint256 indexed campaignId,
        address indexed donor,
        uint256 amount,
        uint256 timestamp
    );

    event WithdrawalRequested(
        uint256 indexed campaignId,
        uint256 indexed requestId,
        uint256 requestedAmount,
        string proofIpfsHash
    );

    event WithdrawalApproved(
        uint256 indexed campaignId,
        uint256 indexed requestId,
        address indexed creator,
        uint256 amountReleased,
        uint256 platformFee
    );

    event WithdrawalRejected(
        uint256 indexed campaignId,
        uint256 indexed requestId,
        string reason
    );

    event CampaignCancelled(uint256 indexed campaignId);

    event DonorRefunded(
        uint256 indexed campaignId,
        address indexed donor,
        uint256 amount
    );

    // ─────────────────────────────────────────────────────────────────────────
    // Modifiers
    // ─────────────────────────────────────────────────────────────────────────

    modifier onlyAdmin() {
        require(msg.sender == admin, "Not admin");
        _;
    }

    modifier campaignExists(uint256 campaignId) {
        require(campaignId > 0 && campaignId <= campaignCounter, "Campaign does not exist");
        _;
    }

    modifier onlyCreator(uint256 campaignId) {
        require(campaigns[campaignId].creator == msg.sender, "Not campaign creator");
        _;
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Constructor
    // ─────────────────────────────────────────────────────────────────────────

    constructor() {
        admin = msg.sender;
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Campaign lifecycle
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @dev Create a new campaign. The creator's wallet address is the beneficiary.
     * @param targetAmount  Fundraising goal in wei
     * @param durationDays  Campaign duration in days
     * @param ipfsHash      IPFS CID of the campaign metadata/document bundle
     */
    function createCampaign(
        uint256 targetAmount,
        uint256 durationDays,
        string calldata ipfsHash
    ) external returns (uint256) {
        require(targetAmount > 0, "Target must be > 0");
        require(durationDays > 0 && durationDays <= 365, "Duration: 1-365 days");

        campaignCounter++;
        uint256 id = campaignCounter;
        uint256 deadline = block.timestamp + (durationDays * 1 days);

        campaigns[id] = Campaign({
            id: id,
            creator: payable(msg.sender),
            targetAmount: targetAmount,
            amountRaised: 0,
            deadline: deadline,
            status: CampaignStatus.Active,
            ipfsMetadataHash: ipfsHash,
            createdAt: block.timestamp
        });

        creatorCampaigns[msg.sender].push(id);

        emit CampaignCreated(id, msg.sender, targetAmount, deadline, ipfsHash);
        return id;
    }

    /**
     * @dev Donate ETH to a campaign. Funds are held in this contract (escrow).
     */
    function donate(uint256 campaignId) external payable campaignExists(campaignId) {
        require(msg.value > 0, "Donation must be > 0");

        Campaign storage c = campaigns[campaignId];
        require(
            c.status == CampaignStatus.Active || c.status == CampaignStatus.Funded,
            "Campaign not accepting donations"
        );
        require(block.timestamp <= c.deadline, "Campaign deadline passed");

        c.amountRaised += msg.value;
        donorContributions[campaignId][msg.sender] += msg.value;
        _campaignDonors[campaignId].push(msg.sender);
        _campaignDonationAmounts[campaignId].push(msg.value);

        if (c.amountRaised >= c.targetAmount) {
            c.status = CampaignStatus.Funded;
        }

        emit DonationReceived(campaignId, msg.sender, msg.value, block.timestamp);
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Withdrawal requests (creator)
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @dev Creator submits a withdrawal request with proof of milestone completion.
     * @param campaignId      Campaign to withdraw from
     * @param requestedAmount Amount in wei being requested
     * @param proofIpfsHash   IPFS CID of proof bundle (invoice, receipt, photo)
     */
    function submitWithdrawalRequest(
        uint256 campaignId,
        uint256 requestedAmount,
        string calldata proofIpfsHash
    ) external campaignExists(campaignId) onlyCreator(campaignId) {
        Campaign storage c = campaigns[campaignId];
        require(
            c.status == CampaignStatus.Active || c.status == CampaignStatus.Funded,
            "Campaign not eligible for withdrawal"
        );
        require(requestedAmount > 0, "Amount must be > 0");
        require(requestedAmount <= c.amountRaised, "Insufficient campaign balance");
        require(bytes(proofIpfsHash).length > 0, "Proof hash required");

        uint256 requestId = _withdrawalRequests[campaignId].length;

        _withdrawalRequests[campaignId].push(WithdrawalRequest({
            id: requestId,
            campaignId: campaignId,
            requestedAmount: requestedAmount,
            proofIpfsHash: proofIpfsHash,
            status: RequestStatus.Pending,
            rejectionReason: "",
            createdAt: block.timestamp
        }));

        emit WithdrawalRequested(campaignId, requestId, requestedAmount, proofIpfsHash);
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Admin: approve / reject withdrawals
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @dev Approve a withdrawal request. Releases ETH to the creator minus
     *      the platform fee.
     */
    function approveWithdrawal(
        uint256 campaignId,
        uint256 requestId
    ) external onlyAdmin campaignExists(campaignId) {
        WithdrawalRequest storage req = _withdrawalRequests[campaignId][requestId];
        require(req.status == RequestStatus.Pending, "Request not pending");

        Campaign storage c = campaigns[campaignId];
        require(req.requestedAmount <= c.amountRaised, "Insufficient campaign balance");

        uint256 fee = (req.requestedAmount * platformFeePercent) / 100;
        uint256 payout = req.requestedAmount - fee;

        req.status = RequestStatus.Approved;
        c.amountRaised -= req.requestedAmount;
        platformFeesCollected += fee;

        (bool ok, ) = c.creator.call{value: payout}("");
        require(ok, "Transfer to creator failed");

        emit WithdrawalApproved(campaignId, requestId, c.creator, payout, fee);
    }

    /**
     * @dev Reject a withdrawal request with a reason (shown to creator in UI).
     */
    function rejectWithdrawal(
        uint256 campaignId,
        uint256 requestId,
        string calldata reason
    ) external onlyAdmin campaignExists(campaignId) {
        WithdrawalRequest storage req = _withdrawalRequests[campaignId][requestId];
        require(req.status == RequestStatus.Pending, "Request not pending");

        req.status = RequestStatus.Rejected;
        req.rejectionReason = reason;

        emit WithdrawalRejected(campaignId, requestId, reason);
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Admin: cancel campaign
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @dev Admin cancels a campaign. Enables permissionless donor refunds.
     */
    function cancelCampaign(uint256 campaignId) external onlyAdmin campaignExists(campaignId) {
        Campaign storage c = campaigns[campaignId];
        require(c.status != CampaignStatus.Cancelled, "Already cancelled");
        c.status = CampaignStatus.Cancelled;
        emit CampaignCancelled(campaignId);
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Donor: claim refund
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @dev Any donor can claim their refund when:
     *      (a) campaign is cancelled, OR
     *      (b) deadline passed and target was never reached.
     */
    function claimRefund(uint256 campaignId) external campaignExists(campaignId) {
        Campaign storage c = campaigns[campaignId];
        bool deadlineMissed = block.timestamp > c.deadline &&
                              c.amountRaised < c.targetAmount &&
                              c.status == CampaignStatus.Active;
        bool cancelled = c.status == CampaignStatus.Cancelled;

        require(deadlineMissed || cancelled, "Refund not available");

        uint256 contribution = donorContributions[campaignId][msg.sender];
        require(contribution > 0, "No contribution to refund");

        donorContributions[campaignId][msg.sender] = 0;
        c.amountRaised -= contribution;

        if (deadlineMissed) {
            c.status = CampaignStatus.Cancelled;
        }

        (bool ok, ) = payable(msg.sender).call{value: contribution}("");
        require(ok, "Refund transfer failed");

        emit DonorRefunded(campaignId, msg.sender, contribution);
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Admin: collect platform fees
    // ─────────────────────────────────────────────────────────────────────────

    function withdrawPlatformFees() external onlyAdmin {
        uint256 amount = platformFeesCollected;
        require(amount > 0, "No fees to withdraw");
        platformFeesCollected = 0;
        (bool ok, ) = payable(admin).call{value: amount}("");
        require(ok, "Fee withdrawal failed");
    }

    // ─────────────────────────────────────────────────────────────────────────
    // View functions
    // ─────────────────────────────────────────────────────────────────────────

    function getCampaign(uint256 campaignId)
        external view campaignExists(campaignId)
        returns (Campaign memory)
    {
        return campaigns[campaignId];
    }

    function getCampaignDonors(uint256 campaignId)
        external view campaignExists(campaignId)
        returns (address[] memory donors, uint256[] memory amounts)
    {
        return (_campaignDonors[campaignId], _campaignDonationAmounts[campaignId]);
    }

    function getWithdrawalRequests(uint256 campaignId)
        external view campaignExists(campaignId)
        returns (WithdrawalRequest[] memory)
    {
        return _withdrawalRequests[campaignId];
    }

    function getCreatorCampaigns(address creator)
        external view
        returns (uint256[] memory)
    {
        return creatorCampaigns[creator];
    }

    function getContractBalance() external view returns (uint256) {
        return address(this).balance;
    }
}

